.0369C178.468 20.1729 178.468 20.3089 178.468 20.4449C178.468 20.5538 178.468 20.6762 178.468 20.8122C178.495 20.921 178.523 21.0299 178.55 21.1387C178.55 21.1659 178.591 21.2475 178.672 21.3835C178.754 21.5196 178.795 21.6012 178.795 21.6284L178.917 21.7508C178.972 21.778 179.053 21.778 179.162 21.7508C179.298 21.7236 179.393 21.7372 179.448 21.7916C179.693 21.8188 180.005 21.6964 180.386 21.4243C180.794 21.1251 181.162 20.7986 181.488 20.4449C181.57 20.3633 181.651 20.3225 181.733 20.3225C181.787 20.3225 181.828 20.3633 181.855 20.4449C181.883 20.5266 181.855 20.6354 181.774 20.7714C181.338 21.3971 180.93 21.8324 180.549 22.0773C180.169 22.2949 179.815 22.4037 179.488 22.4037Z"
                fill="#FF7A18"
              />
            </svg>

            <h2
              class="font-inter font-medium text-[24px] leading-[34px] tracking-[0%] text-gray-900"
            >
              Create Your Account
            </h2>
          </div>

          <!-- Form -->
          <form class="space-y-6">
            <!-- Email -->
            <div>
              <label class="block text-sm font-medium text-gray-700 mb-1.5">
                Email
              </label>
              <div class="relative">
                <div
                  class="absolute inset-y-0 left-0 pl-3.5 flex items-center pointer-events-none"
                >
                  <svg
                    class="h-5 w-5 text-gray-400"
                    fill="currentColor"
                    viewBox="0 0 20 20"
                  >
                    <path
                      d="M2.003 5.884L10 9.882l7.997-3.998A2 2 0 0016 4H4a2 2 0 00-1.997 1.884z"
                    />
                    <path
                      d="M18 8.118l-8 4-8-4V14a2 2 0 002 2h12a2 2 0 002-2V8.118z"
                    />
                  </svg>
                </div>
                <input
                  v-model="email"
                  type="email"
                  placeholder="name@gmail.com"
                  class="block w-full pl-11 pr-4 py-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-orange-500 focus:border-transparent transition"
                />
              </div>
            </div>

            <!-- Phone -->
            <div>
              <label class="block text-sm font-medium text-gray-700 mb-1.5">
                Phone number
              </label>
              <div class="relative">
                <div
                  class="absolute inset-y-0 left-0 pl-3.5 flex items-center pointer-events-none"
                >
                  <svg
                    class="h-5 w-5 text-gray-400"
                    fill="currentColor"
                    viewBox="0 0 20 20"
                  >
                    <path
                      d="M2 3a1 1 0 011-1h2.153a1 1 0 01.986.836l.74 4.435a1 1 0 01-.54 1.06l-1.81.905a16.113 16.113 0 006.416 6.416l.905-1.81a1 1 0 011.06-.54l4.435.74a1 1 0 01.836.986V17a1 1 0 01-1 1h-2C7.82 18 2 12.18 2 5V3z"
                    />
                  </svg>
                </div>
                <input
                  v-model="phone"
                  type="tel"
                  placeholder="+234 801 234 5678"
                  class="block w-full pl-11 pr-4 py-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-orange-500 focus:border-transparent transition"
                />
              </div>
            </div>

            <!-- Password -->
            <div>
              <label class="block text-sm font-medium text-gray-700 mb-1.5">
                Password
              </label>
              <div class="relative">
                <div
                  class="absolute inset-y-0 left-0 pl-3.5 flex items-center pointer-events-none"
                >
                  <svg
                    class="h-5 w-5 text-gray-400"
                    fill="currentColor"
                    viewBox="0 0 20 20"
                  >
                    <path
                      fill-rule="evenodd"
                      d="M5 9V7a5 5 0 0110 0v2a2 2 0 012 2v5a2 2 0 01-2 2H5a2 2 0 01-2-2v-5a2 2 0 012-2zm8-2v2H7V7a3 3 0 016 0z"
                      clip-rule="evenodd"
                    />
                  </svg>
                </div>
                <input
                  v-model="password"
                  :type="showPassword ? 'text' : 'password'"
                  placeholder="••••••••"
                  class="block w-full pl-11 pr-12 py-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-orange-500 focus:border-transparent transition"
                />
                <button
                  type="button"
                  @click="showPassword = !showPassword"
                  class="absolute inset-y-0 right-0 pr-3.5 flex items-center text-gray-400 hover:text-gray-600"
                >
                  <!-- eye icons same as before -->
                  <svg
                    v-if="!showPassword"
                    class="h-5 w-5"
                    fill="currentColor"
                    viewBox="0 0 20 20"
                  >
                    <path d="M10 12a2 2 0 100-4 2 2 0 000 4z" />
                    <path
                      fill-rule="evenodd"
                      d="M.458 10C1.732 5.943 5.522 3 10 3s8.268 2.943 9.542 7c-1.274 4.057-5.064 7-9.542 7S1.732 14.057.458 10zM14 10a4 4 0 11-8 0 4 4 0 018 0z"
                      clip-rule="evenodd"
                    />
                  </svg>
                  <svg
                    v-else
                    class="h-5 w-5"
                    fill="currentColor"
                    viewBox="0 0 20 20"
                  >
                    <!-- crossed eye icon -->
                    <path
                      fill-rule="evenodd"
                      d="M3.707 2.293a1 1 0 00-1.414 1.414l14 14a1 1 0 001.414-1.414l-1.473-1.473A10.014 10.014 0 0019.542 10C18.268 5.943 14.478 3 10 3a9.958 9.958 0 00-4.512 1.074l-1.78-1.781zm4.261 4.26l1.514 1.515a2.003 2.003 0 012.45 2.45l1.514 1.514a4 4 0 00-5.478-5.478z"
                      clip-rule="evenodd"
                    />
                    <path
                      d="M15.171 11.586a4 4 0 111.414-1.414l1.473 1.473c.078.088.157.177.235.266A10.015 10.015 0 0119.542 10c-1.274-4.057-5.064-7-9.542-7a9.958 9.958 0 00-4.512 1.074l1.781 1.781a7.977 7.977 0 019.354 9.33z"
                    />
                  </svg>
                </button>
              </div>
            </div>

            <!-- Confirm Password -->
            <div>
              <label class="block text-sm font-medium text-gray-700 mb-1.5">
                Confirm password
              </label>
              <div class="relative">
                <div
                  class="absolute inset-y-0 left-0 pl-3.5 flex items-center pointer-events-none"
                >
                  <svg
                    class="h-5 w-5 text-gray-400"
                    fill="currentColor"
                    viewBox="0 0 20 20"
                  >
                    <path
                      fill-rule="evenodd"
                      d="M5 9V7a5 5 0 0110 0v2a2 2 0 012 2v5a2 2 0 01-2 2H5a2 2 0 01-2-2v-5a2 2 0 012-2zm8-2v2H7V7a3 3 0 016 0z"
                      clip-rule="evenodd"
                    />
                  </svg>
                </div>
                <input
                  v-model="confirmPassword"
                  type="password"
                  placeholder="••••••••"
                  class="block w-full pl-11 pr-4 py-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-orange-500 focus:border-transparent transition"
                />
              </div>
            </div>

            <!-- Terms Checkbox -->
            <div class="flex items-start space-x-3 mb-6">
              <input
                v-model="acceptTerms"
                type="checkbox"
                id="terms"
                class="mt-1 w-5 h-5 text-blue-600 bg-white border-gray-300 rounded focus:ring-blue-500 focus:ring-2 cursor-pointer"
              />
              <label
                for="terms"
                class="text-sm text-gray-700 cursor-pointer leading-5"
              >
                I agree to the
                <a
                  href="#"
                  class="text-blue-500 hover:text-blue-600 font-medium underline"
                >
                  Terms & Conditions
                </a>
                and
                <a
                  href="#"
                  class="text-blue-500 hover:text-blue-600 font-medium underline"
                >
                  Privacy Policy
                </a>
              </label>
            </div>

            <!-- Continue Button -->
            <button
              type="button"
              @click="handleSignup"
              class="w-full bg-orange-500 hover:bg-orange-600 text-white font-bold py-3.5 rounded-lg transition duration-200 shadow-sm"
              :disabled="!acceptTerms"
            >
              Continue
            </button>
          </form>

          <!-- Divider -->
          <div class="relative py-2">
            <div class="absolute inset-0 flex items-center"></div>
            <div class="relative flex justify-center text-sm">
              <span class="px-4 bg-white text-gray-500">Or continue with</span>
            </div>
          </div>

          <!-- Social Buttons -->
          <div class="grid grid-cols-1 gap-4">
            <button
              class="flex items-center justify-center gap-3 border border-gray-300 py-3 rounded-lg hover:bg-gray-50 transition"
            >
              <!-- Google icon (you can keep your SVG or use img) -->
              <img src="/google.png" alt="Google" class="h-5 w-5" />
              Continue with Google
            </button>

            <button
              class="flex items-center justify-center gap-3 border border-gray-300 py-3 rounded-lg hover:bg-gray-50 transition"
            >
              <img src="/facebook.png" alt="Apple" class="h-5 w-5" />
              Continue with Facebook
            </button>
          </div>

          <!-- Already have account -->
          <p class="text-center text-sm text-gray-600 mt-8">
            Already have an account?
            <a href="#" class="text-blue-600 hover:underline font-medium">
              Sign in
            </a>
          </p>
        </div>
      </div>
    </div>
    <footer
      class="hidden lg:block bg-[#4B3621] text-white py-16 px-6 lg:px-24 relative"
    >
      <div
        class="max-w-7xl mx-auto grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-12"
      >
        <div>
          <svg
            width="165"
            height="29"
            viewBox="0 0 165 29"
            fill="none"
            xmlns="http://www.w3.org/2000/svg"
